mapper.select:
SELECT a.* FROM (SELECT c.collection_id, doc.bus_id AS doc_id, doc.doc_name, doc.doc_suffix, doc.type, doc.doc_size, CASE WHEN docg.doc_name IS NULL THEN CASE WHEN doc.type = 0 THEN h.house_name || '/' || doc.doc_name ELSE h.house_name END ELSE CASE WHEN doc.type = 0 THEN h.house_name || '/' || docg.doc_name || '/' || doc.doc_name ELSE h.house_name || '/' || docg.doc_name END END AS folder, doc.doc_owner AS user_id, CASE WHEN doc.type = 0 THEN NULL ELSE doc.doc_owner END AS docOwnerName, doc.update_time, c.create_time AS collection_time, doc.doc_type AS docLibraryType, doc.folder_id AS lastFolderId, doc.house_id AS documentHouseId, doc.is_deleted AS is_deleted, CASE WHEN us.doc_id IS NOT NULL OR doc.doc_type = 1 THEN 1 ELSE 0 END AS isAsh, CASE WHEN doc.recycle_status = 1 THEN 0 ELSE 1 END AS isRecovery, CASE WHEN doc.doc_status = 3 THEN 0 ELSE 1 END AS isNoSelf FROM doc_bs_document doc LEFT JOIN doc_sys_house h ON h.house_id = doc.house_id JOIN doc_bs_collection c ON c.doc_id = doc.bus_id AND c.user_id = #{userId} AND c.is_deleted = 0 LEFT JOIN (SELECT t.doc_id, LISTAGG(d.doc_name, '/') WITHIN GROUP (ORDER BY d.folder_level) doc_name FROM doc_bs_document_tree t LEFT JOIN doc_bs_document d ON d.bus_id = t.father_id WHERE doc_id IN
#{item}
GROUP BY t.doc_id ) docg ON doc.folder_id = docg.doc_id LEFT JOIN (SELECT DISTINCT doc_id FROM doc_bs_document_user WHERE is_deleted = 0 AND rel_id IN
#{item}
) us ON us.doc_id = doc.bus_id ) a
JOIN (SELECT doc_id FROM doc_bs_tag_document WHERE tag_id IN
#{item}
) t ON t.doc_id = a.doc_id
AND a.doc_name LIKE '%' || #{docName} || '%'
AND a.collection_time BETWEEN #{collectionTimeTo} AND #{collectionTimeDo}
ORDER BY a.collection_time ASC
ORDER BY a.collection_time DESC
ORDER BY a.update_time ASC
ORDER BY a.update_time DESC
ORDER BY a.collection_time DESC
